# solution.py
"""Team Collaboration Manager.

A single-file, standard-library-only implementation of an in-memory team
collaboration backend.  It manages users, projects, tasks, messaging,
performance metrics and report generation.  All mutating operations are
guarded by a single shared re-entrant lock so the manager is safe to use
from multiple threads.

The public surface (classes, enums and the ``TeamCollaborationManager``
methods) is exercised by ``test_solution.py``.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with the current state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    VIEWER = "viewer"
    MEMBER = "member"
    EDITOR = "editor"
    ADMIN = "admin"


class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores (thin namespaces that share one lock)
# ---------------------------------------------------------------------------
class _BaseStore:
    """Holds the shared lock so all stores expose identical ``_lock``."""

    def __init__(self, lock):
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id = {}            # type: Dict[int, User]
        self.by_username = {}      # type: Dict[str, int]
        self.by_email = {}         # type: Dict[str, int]


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id = {}            # type: Dict[int, Project]


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id = {}            # type: Dict[int, Task]
        self.by_project = {}       # type: Dict[int, List[int]]
        self.by_assignee = {}      # type: Dict[int, set]


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id = {}            # type: Dict[int, Message]
        self.by_project = {}       # type: Dict[int, List[int]]
        self.by_task = {}          # type: Dict[int, List[int]]


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.ratings_by_id = {}    # type: Dict[int, Rating]
        self.ratings_by_ratee = {}  # type: Dict[int, List[int]]


class _ReportStore(_BaseStore):
    pass


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory, thread-safe team collaboration backend."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        # Sub-stores all share the single lock instance.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- helpers -----------------------------------------------------------
    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    def _require_user(self, user_id) -> User:
        user = self.users.by_id.get(user_id)
        if user is None:
            raise NotFoundError("user not found: {0}".format(user_id))
        return user

    def _require_project(self, project_id) -> Project:
        project = self.projects.by_id.get(project_id)
        if project is None:
            raise NotFoundError("project not found: {0}".format(project_id))
        return project

    def _require_task(self, task_id) -> Task:
        task = self.tasks.by_id.get(task_id)
        if task is None:
            raise NotFoundError("task not found: {0}".format(task_id))
        return task

    def _require_message(self, message_id) -> Message:
        message = self.messages.by_id.get(message_id)
        if message is None:
            raise NotFoundError("message not found: {0}".format(message_id))
        return message

    @staticmethod
    def _clean_text(value, label):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} is required".format(label))
        return value.strip()

    @staticmethod
    def _validate_email(value):
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("email is required")
        cleaned = value.strip()
        if "@" not in cleaned:
            raise ValidationError("email is invalid")
        return cleaned

    # ------------------------------------------------------------------ #
    # User management
    # ------------------------------------------------------------------ #
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        clean_username = self._clean_text(username, "username")
        clean_email = self._validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role is invalid")
        with self._lock:
            if clean_username in self.users.by_username:
                raise DuplicateError("username already exists")
            if clean_email in self.users.by_email:
                raise DuplicateError("email already exists")
            user_id = self._next_id()
            user = User(
                id=user_id,
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users.by_id[user_id] = user
            self.users.by_username[clean_username] = user_id
            self.users.by_email[clean_email] = user_id
            return copy.deepcopy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                copy.deepcopy(self.users.by_id[uid])
                for uid in sorted(self.users.by_id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_username = None
            if username is not None:
                new_username = self._clean_text(username, "username")
                owner = self.users.by_username.get(new_username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")

            new_email = None
            if email is not None:
                new_email = self._validate_email(email)
                owner = self.users.by_email.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role is invalid")

            if new_username is not None:
                self.users.by_username.pop(user.username, None)
                user.username = new_username
                self.users.by_username[new_username] = user_id
            if new_email is not None:
                self.users.by_email.pop(user.email, None)
                user.email = new_email
                self.users.by_email[new_email] = user_id
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)
            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task_id in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.by_id.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")
            del self.users.by_id[user_id]
            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)
            self.tasks.by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------ #
    # Project management
    # ------------------------------------------------------------------ #
    def create_project(self, name, start_date, end_date, owner_id,
                       description="") -> Project:
        clean_name = self._clean_text(name, "name")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")
        with self._lock:
            self._require_user(owner_id)
            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects.by_id[project_id] = project
            self.tasks.by_project.setdefault(project_id, [])
            self.messages.by_project.setdefault(project_id, [])
            return copy.deepcopy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                copy.deepcopy(self.projects.by_id[pid])
                for pid in sorted(self.projects.by_id)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = None
            if name is not None:
                new_name = self._clean_text(name, "name")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if new_name is not None:
                project.name = new_name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            for task_id in list(self.tasks.by_project.get(project_id, [])):
                task = self.tasks.by_id.pop(task_id, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    assigned = self.tasks.by_assignee.get(task.assignee_id)
                    if assigned is not None:
                        assigned.discard(task_id)
                for msg_id in list(self.messages.by_task.get(task_id, [])):
                    self.messages.by_id.pop(msg_id, None)
                self.messages.by_task.pop(task_id, None)
            self.tasks.by_project.pop(project_id, None)

            for msg_id in list(self.messages.by_project.get(project_id, [])):
                self.messages.by_id.pop(msg_id, None)
            self.messages.by_project.pop(project_id, None)

            del self.projects.by_id[project_id]

    # ------------------------------------------------------------------ #
    # Task management
    # ------------------------------------------------------------------ #
    def create_task(self, project_id, title, assignee_id=None,
                   deadline=None) -> Task:
        clean_title = self._clean_text(title, "title")
        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot be before project start")
            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.by_id[task_id] = task
            self.tasks.by_project.setdefault(project_id, []).append(task_id)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            task_ids = sorted(self.tasks.by_project.get(project_id, []))
            return [
                copy.deepcopy(self.tasks.by_id[tid])
                for tid in task_ids
                if tid in self.tasks.by_id
            ]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            task_ids = sorted(self.tasks.by_assignee.get(assignee_id, set()))
            return [
                copy.deepcopy(self.tasks.by_id[tid])
                for tid in task_ids
                if tid in self.tasks.by_id
            ]

    def _move_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old == new_assignee_id:
            if new_assignee_id is not None:
                self.tasks.by_assignee.setdefault(new_assignee_id, set()).add(task.id)
            return
        if old is not None:
            assigned = self.tasks.by_assignee.get(old)
            if assigned is not None:
                assigned.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks.by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._move_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._move_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._move_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline cannot be before project start"
                    )
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status is invalid")
        with self._lock:
            task = self._require_task(task_id)
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------ #
    # Messaging
    # ------------------------------------------------------------------ #
    def post_message(self, author_id, body, project_id=None, task_id=None,
                    parent_id=None, attachments=None) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachments = attachments or []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachments:
                raise ValidationError("message body or attachment is required")

            now = self._now()
            attachment_objs = []
            for filename, data in attachments:
                attachment_objs.append(
                    Attachment(
                        filename=filename,
                        size=len(data),
                        uploaded_by=author_id,
                        uploaded_at=now,
                    )
                )

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self.messages.by_id[message_id] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, []).append(message_id)
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, []).append(message_id)
            return copy.deepcopy(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            clean_body = new_body if isinstance(new_body, str) else ""
            if not clean_body.strip():
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may add an attachment"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename is required")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._now(),
                )
            )
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            msg_ids = sorted(self.messages.by_project.get(project_id, []))
            return [
                copy.deepcopy(self.messages.by_id[mid])
                for mid in msg_ids
                if mid in self.messages.by_id
            ]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            msg_ids = sorted(self.messages.by_task.get(task_id, []))
            return [
                copy.deepcopy(self.messages.by_id[mid])
                for mid in msg_ids
                if mid in self.messages.by_id
            ]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            self.messages.by_id.pop(message_id, None)
            if message.project_id is not None:
                bucket = self.messages.by_project.get(message.project_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = self.messages.by_task.get(message.task_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)

    # ------------------------------------------------------------------ #
    # Performance dashboard
    # ------------------------------------------------------------------ #
    def _assigned_tasks(self, user_id) -> List[Task]:
        return [
            self.tasks.by_id[tid]
            for tid in self.tasks.by_assignee.get(user_id, set())
            if tid in self.tasks.by_id
        ]

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._assigned_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                     task_id=None) -> Rating:
        if isinstance(score, bool) or not isinstance(score, int):
            raise ValidationError("score must be an integer between 1 and 5")
        if score < 1 or score > 5:
            raise ValidationError("score must be between 1 and 5")
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings_by_id[rating_id] = rating
            self.performance.ratings_by_ratee.setdefault(ratee_id, []).append(
                rating_id
            )
            return copy.deepcopy(rating)

    def _ratings_for(self, user_id) -> List[Rating]:
        return [
            self.performance.ratings_by_id[rid]
            for rid in self.performance.ratings_by_ratee.get(user_id, [])
            if rid in self.performance.ratings_by_id
        ]

    def get_ratings_summary(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            average_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------ #
    # Reports
    # ------------------------------------------------------------------ #
    def project_progress_report(self, project_id) -> Dict:
        with self._lock:
            self._require_project(project_id)
            now = self._now()
            tasks = [
                self.tasks.by_id[tid]
                for tid in self.tasks.by_project.get(project_id, [])
                if tid in self.tasks.by_id
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            completed = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> Dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                pool = [
                    self.tasks.by_id[tid]
                    for tid in self.tasks.by_project.get(project_id, [])
                    if tid in self.tasks.by_id
                ]
            else:
                pool = list(self.tasks.by_id.values())

            grouped = {}
            for task in pool:
                if task.assignee_id is None:
                    continue
                grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                tasks = grouped[user_id]
                total = len(tasks)
                completed = sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                )
                durations = self._completion_durations(tasks)
                average_time = (
                    sum(durations) / len(durations) if durations else None
                )
                ratings = self._ratings_for(user_id)
                rating_average = (
                    sum(r.score for r in ratings) / len(ratings)
                    if ratings
                    else 0.0
                )
                rows.append(
                    {
                        "user_id": user_id,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": (completed / total)
                        if total
                        else 0.0,
                        "average_completion_time": average_time,
                        "rating_average": rating_average,
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> Dict:
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(
                self._assigned_tasks(user_id), key=lambda t: t.id
            )
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            durations = self._completion_durations(tasks)
            average_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [copy.deepcopy(t) for t in tasks],
            }

    # ------------------------------------------------------------------ #
    # Report export
    # ------------------------------------------------------------------ #
    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format is invalid")
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping")
        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        if report_format == ReportFormat.PDF:
            return self._export_pdf(report)
        raise ValidationError("unsupported report format")

    @staticmethod
    def _scalar(value) -> str:
        if isinstance(value, Enum):
            return str(value.value)
        return str(value)

    def _stringify(self, value) -> str:
        if isinstance(value, dict):
            return "; ".join(
                "{0}={1}".format(k, self._scalar(v)) for k, v in value.items()
            )
        if isinstance(value, (list, tuple)):
            return " | ".join(self._scalar(v) for v in value)
        return self._scalar(value)

    def _export_csv(self, report) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        writer.writerow(["field", "value"])
        for key in sorted(report.keys(), key=str):
            writer.writerow([str(key), self._stringify(report[key])])
        return buffer.getvalue()

    @staticmethod
    def _pdf_escape(text) -> str:
        text = str(text)
        text = text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        return text.replace("\r", " ").replace("\n", " ")

    def _build_pdf_content(self, lines) -> bytes:
        parts = ["BT", "/F1 10 Tf", "50 760 Td", "14 TL"]
        if not lines:
            lines = [""]
        for index, line in enumerate(lines):
            if index == 0:
                parts.append("({0}) Tj".format(self._pdf_escape(line)))
            else:
                parts.append("T*")
                parts.append("({0}) Tj".format(self._pdf_escape(line)))
        parts.append("ET")
        return "\n".join(parts).encode("latin-1", "replace")

    def _export_pdf(self, report) -> bytes:
        lines = [
            "{0}: {1}".format(key, self._stringify(report[key]))
            for key in sorted(report.keys(), key=str)
        ]
        content = self._build_pdf_content(lines)
        object_bodies = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray()
        pdf += b"%PDF-1.4\n"
        offsets = []
        for number, body in enumerate(object_bodies, start=1):
            offsets.append(len(pdf))
            pdf += str(number).encode("ascii") + b" 0 obj\n"
            pdf += body
            pdf += b"\nendobj\n"

        xref_offset = len(pdf)
        size = len(object_bodies) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_offset).encode("ascii") + b"\n"
        pdf += b"%%EOF"
        return bytes(pdf)


